def __init__(self, runtime: 'AuroraUnifiedRuntimeV2'):
        self.runtime = runtime
        self.running = False
        self.evolution_thread: Optional[threading.Thread] = None

        # Evolution state
        self.evolution_generation = 0
        self.tick_count = 0
        self.last_evolution_time = time.time()

        # Intervals
        self.evolution_interval = 30.0  # seconds between evolution ticks
        self.background_tick_interval = 5.0  # seconds between background ticks

        # Harvested knowledge
        self.harvested_concepts: List[Dict] = []
        self.evolution_insights: List[str] = []

        print("[CONTINUOUS_EVOLUTION] Engine initialized")

    def start(self):
        """Start background evolution."""
        self.running = True
        self.evolution_thread = threading.Thread(target=self._evolution_loop, daemon=True)
        self.evolution_thread.start()
        print("[CONTINUOUS_EVOLUTION] Background evolution started")

    def stop(self):
        """Stop background evolution."""
        self.running = False
        if self.evolution_thread:
            self.evolution_thread.join(timeout=2.0)
        print("[CONTINUOUS_EVOLUTION] Background evolution stopped")

    def _evolution_loop(self):
        """Main evolution loop - runs continuously."""
        while self.running:
            try:
                self.tick_count += 1

                # Background tick
                self._background_tick()

                # Evolution tick (less frequent)
                if time.time() - self.last_evolution_time > self.evolution_interval:
                    self._evolution_tick()
                    self.last_evolution_time = time.time()

                time.sleep(self.background_tick_interval)

            except Exception as e:
                print(f"[CONTINUOUS_EVOLUTION] Error: {e}")
                time.sleep(1.0)

    def _background_tick(self):
        """Run background processes."""
        # Evolve I-State beings
        if self.runtime.i_universe:
            try:
                self.runtime.i_universe.run_full_cycle()
            except Exception:
                pass

        # Energy regulation tick
        if self.runtime.energy_regulator:
            try:
                self.runtime.energy_regulator.step_optimized(dt=0.1)
            except Exception:
                pass

    def _evolution_tick(self):
        """Run evolution cycle."""
        self.evolution_generation += 1

        # Evolve DPS
        if self.runtime.dps:
            try:
                self.runtime.dps.evolve_processing()
            except Exception:
                pass

        # Evolve energy
        if self.runtime.energy_regulator:
            try:
                self.runtime.energy_regulator.evolve_energy()
            except Exception:
                pass

        # DNA evolution
        if self.runtime.dna_system:
            try:
                self.runtime.dna_system.apply_alleles_to_genes()
            except Exception:
                pass

        # Form relics in aligned stack
        if self.runtime.aligned_stack:
            try:
                relics = self.runtime.aligned_stack.form_relics()
                if relics:
                    self.evolution_insights.append(
                        f"Gen {self.evolution_generation}: Formed {len(relics)} relics"
                    )
            except Exception:
                pass

    def get_status(self) -> Dict[str, Any]:
        """Get evolution status."""
        return {
            "running": self.running,
            "evolution_generation": self.evolution_generation,
            "tick_count": self.tick_count,
            "harvested_concepts": len(self.harvested_concepts),
            "evolution_insights": len(self.evolution_insights)
        }

